ps.pstext:
if !IsFeatureImplemented(FEAT_FP) then EndOfDecode(Decode_UNDEF); end;
if ftype == '10' then EndOfDecode(Decode_UNDEF); end;
if ftype == '11' && !IsFeatureImplemented(FEAT_FP16) then EndOfDecode(Decode_UNDEF); end;
if sf == '0' && scale[5] == '0' then EndOfDecode(Decode_UNDEF); end;

let d : integer{} = UInt(Rd);
let n : integer{} = UInt(Rn);

let intsize : integer{} = 32 << UInt(sf);
let decode_fltsize : integer{} = 8 << UInt(ftype XOR '10');

let fracbits : integer = 64 - UInt(scale);

let unsigned : boolean = TRUE;

AArch64_CheckFPEnabled();

let merge : boolean = IsMerging(FPCR());
let fltsize : integer{} = if merge then 128 else decode_fltsize;
var fltval : bits(fltsize) = if merge then V{fltsize}(d) else Zeros{fltsize};
let intval : bits(intsize) = X{}(n);
let rounding : FPRounding = FPRoundingMode(FPCR());

fltval[0+:decode_fltsize] = FixedToFP{decode_fltsize, intsize}(intval, fracbits, unsigned,
                                                               FPCR(), rounding);

V{fltsize}(d) = fltval;
